const now = new Date();
const nowIso = now.toISOString();
const dailyCap = Number($env.DAILY_SEND_CAP || 10);
const maxFollowups = Number($env.MAX_FOLLOWUPS || 2);
const servicePrompt = String($env.OUTREACH_SYSTEM_PROMPT || `You are writing Telegram outreach for ${$env.OUTREACH_SENDER_NAME || 'OutreachTeam'}.
Offer context: sentiment3 helps crypto projects (pre/post TGE) with CoinMarketCap marketing, token discovery, and trending visibility.
Never invent facts. Keep tone human. One question max.`).trim();
const apiKey = String($env.OPENAI_API_KEY || '').trim();
const safeText = (v, max = 300) => String(v ?? '').replace(/[\u0000-\u001F\u007F]/g, ' ').replace(/[<>]/g, '').replace(/\s+/g, ' ').trim().slice(0, max);

const normalize = (row) => {
  const leadId = String(row.lead_id || '').trim();
  if (!leadId) return null;
  const statusRaw = String(row.status || row.stage || 'NEW').trim();
  const status = statusRaw ? statusRaw.toUpperCase().replace(/\s+/g, '_') : 'NEW';
  const approved = String(row.approved || 'N').toUpperCase() === 'Y' ? 'Y' : 'N';
  const followupCount = Number(row.followup_count || 0);
  const nextFollowupAt = row.next_followup_at ? new Date(row.next_followup_at) : null;
  const dueFollowup = (status === 'SENT' || status === 'FOLLOWUP_DUE') && nextFollowupAt && !Number.isNaN(nextFollowupAt.getTime()) && nextFollowupAt <= now;
  const eligible = (status === 'NEW' || dueFollowup) && !['DNC', 'NOT_INTERESTED', 'REPLIED'].includes(status) && !(status === 'NEED_APPROVAL' && approved !== 'Y') && followupCount < maxFollowups;
  return {
    ...row,
    lead_id: leadId,
    name: row.name || '',
    telegram_username: row.telegram_username || row.username || '',
    telegram_chat_id: row.telegram_chat_id || row.telegram_user_id || '',
    company: row.company || '',
    role: row.role || '',
    source_url: row.source_url || '',
    status,
    approved,
    followup_count: followupCount,
    due_followup: dueFollowup,
    eligible,
  };
};

const candidates = items
  .map(i => normalize(i.json))
  .filter(r => r && r.eligible)
  .sort((a, b) => {
    if (a.due_followup && !b.due_followup) return -1;
    if (!a.due_followup && b.due_followup) return 1;
    return String(a.lead_id).localeCompare(String(b.lead_id));
  })
  .slice(0, dailyCap);

async function fetchResearch(url) {
  if (!url) return '';
  try {
    const ctl = new AbortController();
    const t = setTimeout(() => ctl.abort(), 8000);
    const res = await fetch(url, { signal: ctl.signal, headers: { 'User-Agent': 'Mozilla/5.0 OutreachBot/1.0' } });
    clearTimeout(t);
    if (!res.ok) return '';
    const html = await res.text();
    const title = (html.match(/<title[^>]*>([\s\S]*?)<\/title>/i)?.[1] || '').replace(/\s+/g, ' ').trim();
    const meta = (html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([\s\S]*?)["'][^>]*>/i)?.[1] || '').replace(/\s+/g, ' ').trim();
    const h1 = (html.match(/<h1[^>]*>([\s\S]*?)<\/h1>/i)?.[1] || '').replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
    const snippetParts = [title, h1, meta].filter(Boolean);
    return snippetParts.slice(0, 2).join(' | ').slice(0, 320);
  } catch {
    return '';
  }
}

async function callOpenAi(system, user) {
  if (!apiKey || apiKey.startsWith('replace-with-')) return '';
  const ctl = new AbortController();
  const t = setTimeout(() => ctl.abort(), 20000);
  try {
    const res = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      signal: ctl.signal,
      headers: {
        'Authorization': `Bearer ${apiKey}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'gpt-4o-mini',
        temperature: 0.6,
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user },
        ],
      }),
    });
    if (!res.ok) return '';
    const data = await res.json();
    return String(data?.choices?.[0]?.message?.content || '').replace(/\s+/g, ' ').trim();
  } catch {
    return '';
  } finally {
    clearTimeout(t);
  }
}

async function draftMessage(lead, researchSnippet) {
  const isFollowup = !!lead.due_followup;
  const hardRules = `Hard rules:
- Do not invent company/role details.
- If company/role/research is empty, keep message generic.
- Max 450 characters.
- One question maximum.
- Human tone. No emojis by default.`;
  const userPrompt = isFollowup
    ? `Create a short follow-up Telegram message.
Lead name: ${lead.name || ''}
Company: ${lead.company || ''}
Role: ${lead.role || ''}
Research snippet: ${researchSnippet || ''}
Last message sent: ${lead.last_message_sent || ''}
Memory summary: ${lead.memory_summary || ''}
Last reply: ${lead.last_reply_received || ''}
${hardRules}`
    : `Create a first outreach Telegram message.
Lead name: ${lead.name || ''}
Company: ${lead.company || ''}
Role: ${lead.role || ''}
Research snippet: ${researchSnippet || ''}
${hardRules}`;

  const generated = await callOpenAi(servicePrompt, userPrompt);
  if (generated) return generated.slice(0, 450);

  return (isFollowup
    ? `Hi ${lead.name || ''}, quick follow-up in case this is still relevant. I can share a concise tailored plan if useful. Would that help?`
    : `Hi ${lead.name || ''}, wanted to share a practical idea that may support your current growth goals. If useful, I can send a concise tailored note here. Interested?`).replace(/\s+/g, ' ').trim().slice(0, 450);
}

const out = [];
for (const lead of candidates) {
  const research = await fetchResearch(String(lead.source_url || ''));
  const draft = await draftMessage(lead, research);
  const leadTag = lead.telegram_username ? `@${String(lead.telegram_username).replace(/^@/, '')}` : (lead.telegram_chat_id || 'unknown_target');
  const opsMessage = [
    'Approval Required',
    `lead_id: ${safeText(lead.lead_id, 120)}`,
    `name: ${safeText(lead.name || 'N/A', 120)}`,
    `target: ${safeText(leadTag, 120)}`,
    `research: ${safeText(research || '-', 240)}`,
    '',
    'Draft:',
    safeText(draft, 520),
    '',
    `Text commands: approve ${safeText(lead.lead_id, 120)} | edit ${safeText(lead.lead_id, 120)} <feedback> | skip ${safeText(lead.lead_id, 120)} | dnc ${safeText(lead.lead_id, 120)}`,
  ].join('\n');

  out.push({
    json: {
      ...lead,
      status: 'NEED_APPROVAL',
      approved: 'N',
      approval_feedback: '',
      research_snippet: research,
      draft_message: draft,
      error: '',
      ops_message: opsMessage,
      cb_approve: 'approve',
      cb_edit: 'edit',
      cb_skip: 'skip',
      cb_dnc: 'dnc',
      draft_generated_at: nowIso,
    }
  });
}

return out;
